var theBook = createBibleBook(false, {
  "id":            "1Cor",
  "title":         { "en":"1 Corinthians", "fr":"1 Corinthiens" },
  "chapter_count": 16,
  "langs":         [ "en", "fr" ],

  "descriptions": [
    "[Wikipedia] The First Epistle to the Corinthians, usually referred to as First Corinthians or 1 Corinthians, is a Pauline epistle of the New Testament of the Christian Bible. The epistle is attributed to Paul the Apostle and a co-author named Sosthenes, and is addressed to the Christian church in Corinth.[1 Cor.1:1–2] Scholars believe that Sosthenes was the amanuensis who wrote down the text of the letter at Paul's direction. It addresses various issues that had arisen in the Christian community at Corinth and it is composed in a form of Koine Greek."
  ],

});


